        "import { makeAutoObservable } from 'mobx';\n\nimport type { SocialActivityItemVo } from '../../models';\n\nexport class SocialActivityItem {\n    tradeId = '';\n\n    marketId = '';\n\n    ticker = '';\n\n    price = 0;\n\n    count = 0;\n\n    takerSide = '';\n\n    makerAction = '';\n\n    takerAction = '';\n\n    makerNickname = '';\n\n    takerNickname = '';\n\n    createDate = '';\n\n    constructor(vo: SocialActivityItemVo | undefined = undefined) {\n        if (!!vo) {\n            this.updateFromVo(vo);\n        }\n        makeAutoObservable(this);\n    }\n\n    /**\n     * Update this trade with information from the rest api /users/{userId}/trades\n     */\n    updateFromVo(vo: SocialActivityItemVo): void {\n        this.tradeId = vo.trade_id;\n        this.marketId = vo.market_id;\n        this.ticker = vo.ticker;\n        this.price = vo.price;\n        this.count = vo.count;\n        this.takerSide = vo.taker_side;\n        this.makerAction = vo.maker_action;\n        this.takerAction = vo.taker_action;\n        this.makerNickname = vo.maker_nickname;\n        this.takerNickname = vo.taker_nickname;\n        this.createDate = vo.create_date;\n    }\n}\n",
