        "import { makeAutoObservable } from 'mobx';\n\nimport config from 'utils/config';\n\nimport type { SocialCommentVo, SocialPostProductMetadataVo, SocialPostVo } from '../../models';\n\nexport class SocialPost {\n    id = '';\n\n    marketTitle = '';\n\n    eventTitle = '';\n\n    seriesTitle = '';\n\n    eventLongTitle = '';\n\n    marketTicker = '';\n\n    eventTicker = '';\n\n    seriesTickers: string[] = [];\n\n    nickname = '';\n\n    postType = '';\n\n    postSubtype = '';\n\n    content = '';\n\n    dollarRoi = 0;\n\n    percentageRoi = 0;\n\n    side = '';\n\n    likesCount = 0;\n\n    commentsCount = 0;\n\n    liked = false;\n\n    bookmarked = false;\n\n    bookmarksCount = 0;\n\n    createdTs = 0;\n\n    weight = 0;\n\n    recentCommentContent = '';\n\n    recentCommentNickname = '';\n\n    imagePaths: string[] = [];\n\n    profileImagePath = '';\n\n    productMetadata: SocialPostProductMetadataVo | null = null;\n\n    marketStatus = '';\n\n    marketClose = 0;\n\n    suggestedMarketTitle = '';\n\n    settlementSource = '';\n\n    positionOdds: number | undefined = undefined;\n\n    cost: number | undefined = undefined;\n\n    value: number | undefined = undefined;\n\n    paidOut: number | undefined = undefined;\n\n    payoutIfWin: number | undefined = undefined;\n\n    positionCount: number | undefined = undefined;\n\n    hasEverSold = false;\n\n    loaded = false;\n\n    comments: SocialCommentVo[] = [];\n\n    constructor(vo: SocialPostVo | undefined = undefined) {\n        if (!!vo) {\n            this.updateFromVo(vo);\n        }\n        makeAutoObservable(this);\n    }\n\n    get isYesIdea(): boolean {\n        return this.side === 'yes' && (this.postType === 'idea' || this.postType === 'internal');\n    }\n\n    get isVerified(): boolean {\n        return this.postType === 'internal';\n    }\n\n    get seriesTickerForNavigation(): string {\n        if (this.seriesTickers.length \u003E 0) {\n            return this.seriesTickers[0];\n        }\n        // Should never happen, backend has validation for this\n        return '';\n    }\n\n    get usefulImagePaths(): string[] {\n        return this.imagePaths.filter((path) =\u003E path !== '');\n    }\n\n    get absolutePath(): string {\n        return config.baseUrl + this.relativePath;\n    }\n\n    get relativePath(): string {\n        return '/ideas/posts/' + this.id;\n    }\n\n    get legacyRoiPost(): boolean {\n        return this.payoutIfWin === undefined && this.cost === undefined && this.value === undefined;\n    }\n\n    /**\n     * Update this trade with information from the rest api /users/{userId}/trades\n     */\n    updateFromVo(vo: SocialPostVo): SocialPost {\n        this.id = vo.id;\n        this.marketTitle = vo.market_title;\n        this.eventTitle = vo.event_title;\n        this.seriesTitle = vo.series_title;\n        this.eventLongTitle = vo.event_long_title;\n        this.marketTicker = vo.market_ticker;\n        this.eventTicker = vo.event_ticker;\n        this.seriesTickers = !!vo.series_tickers ? vo.series_tickers : !!vo.series_ticker ? [vo.series_ticker] : [];\n        this.nickname = vo.nickname;\n        this.postType = vo.post_type;\n        this.postSubtype = vo.post_subtype;\n        this.content = vo.content;\n        this.dollarRoi = vo.dollar_roi;\n        this.percentageRoi = vo.percentage_roi;\n        this.side = vo.side;\n        this.likesCount = vo.likes_count;\n        this.commentsCount = vo.comments_count;\n        this.bookmarksCount = vo.bookmarks_count;\n        this.liked = vo.liked;\n        this.bookmarked = vo.bookmarked;\n        this.createdTs = vo.created_ts;\n        this.weight = vo.weight;\n        this.recentCommentContent = vo.recent_comment_content;\n        this.recentCommentNickname = vo.recent_comment_nickname;\n        this.imagePaths = vo.image_paths ?? [];\n        this.profileImagePath = vo.profile_image_path;\n        this.productMetadata = vo.product_metadata ?? null;\n        this.marketStatus = vo.market_status;\n        this.marketClose = vo.market_close;\n        this.suggestedMarketTitle = vo.suggested_market_title;\n        this.settlementSource = vo.settlement_source;\n        this.positionOdds = vo.position_odds;\n        this.cost = vo.cost_cents !== undefined && vo.cost_cents !== null ? vo.cost_cents / 100 : undefined;\n        this.value = vo.value_cents !== undefined && vo.value_cents !== null ? vo.value_cents / 100 : undefined;\n        this.paidOut =\n            vo.paid_out_cents !== undefined && vo.paid_out_cents !== null ? vo.paid_out_cents / 100 : undefined;\n        this.payoutIfWin =\n            vo.payout_if_win_cents !== undefined && vo.payout_if_win_cents !== null\n                ? vo.payout_if_win_cents / 100\n                : undefined;\n        this.positionCount = vo.num_positions_on_event;\n        this.hasEverSold = vo.has_ever_sold ?? false;\n        this.comments = vo.comments ?? [];\n        this.loaded = true;\n\n        return this;\n    }\n}\n",
