        "'use client';\n\nimport type { RootStore } from 'stores/root';\nimport config from 'utils/config';\nimport logProviderFactory from 'utils/logger/logProviderFactory';\n\nimport VendorStore from './vendor';\n\nexport default class FacebookPixelStore extends VendorStore {\n    constructor(rootStore: RootStore) {\n        super(rootStore, 'fb-pixel-script', '');\n    }\n\n    load = (): void =\u003E {\n        try{\n            if (this.startedLoading || this.loaded) return;\n\n            this.startedLoading = true;        \n            import(\"react-facebook-pixel\")\n                .then((x) =\u003E x.default)\n                .then((ReactPixel: any) =\u003E {\n                    ReactPixel.init(config.facebookPixelId, undefined, { debug: false, autoConfig: true})\n                });\n            this.loaded = true;\n        } catch (e) {\n            logProviderFactory.logError('Error loading Facebook Pixel');\n        }\n    };\n\n    trackCustom = (eventName: string, data: any): void =\u003E {\n        try{\n            const utmData = this.root.uiStore.utmData;\n            const payload = {\n                contents: {\n                    ...data,\n                    utm_content: utmData.utm_content,\n                    utm_source: utmData.utm_source,\n                    utm_campaign: utmData.utm_campaign,\n                    utm_term: utmData.utm_term,\n                    utm_medium: utmData.utm_medium,\n                    utm_landing: utmData.utm_landing,\n                }\n            };\n            import(\"react-facebook-pixel\")\n                .then((x) =\u003E x.default)\n                .then((ReactPixel: any) =\u003E {\n                    ReactPixel.trackCustom(eventName, payload);\n                });\n        } catch (e) {\n            logProviderFactory.logError('Error tracking custom event');\n        }\n    }\n}\n",
